    case 1:
      if (lookahead == '"') ADVANCE(25);
      END_STATE();
    case 2:
      if (lookahead == ':') ADVANCE(16);
      if (lookahead == '=') ADVANCE(18);
      if (('\t' <= lookahead && lookahead <= '\r') ||
          lookahead == ' ') SKIP(2);
      END_STATE();
